-- =======================================================
-- WhoIsSpy? Supabase Database Schema & Seed Data
-- Run this in your Supabase SQL Editor to set up the DB.
-- =======================================================

-- 1. Create categories table
create table if not exists public.categories (
    id uuid default gen_random_uuid() primary key,
    name text not null unique,
    is_active boolean default true not null,
    created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 2. Create words table
create table if not exists public.words (
    id uuid default gen_random_uuid() primary key,
    category_id uuid references public.categories(id) on delete cascade not null,
    word text not null,
    created_at timestamp with time zone default timezone('utc'::text, now()) not null,
    constraint unique_category_word unique(category_id, word)
);

-- 3. Enable Row Level Security (RLS)
alter table public.categories enable row level security;
alter table public.words enable row level security;

-- 4. Create public SELECT policies (anyone can read active categories/words)
create policy "Sadece aktif kategorileri herkes okuyabilir"
on public.categories for select
using (is_active = true);

create policy "Kelimeleri herkes okuyabilir"
on public.words for select
using (true);

-- 5. Seed categories (using explicit static UUIDs to prevent duplicates if rerun)
on conflict (name) do update set is_active = excluded.is_active;

-- 6. Seed words (using on conflict do nothing to prevent errors if rerun)

-- Mekanlar
on conflict on constraint unique_category_word do nothing;

-- Meslekler
on conflict on constraint unique_category_word do nothing;

-- Hayvanlar
on conflict on constraint unique_category_word do nothing;

-- Yemekler
on conflict on constraint unique_category_word do nothing;

-- Eşyalar
on conflict on constraint unique_category_word do nothing;
